const body = $input.all()[0].json;
const params = body.parameters;
return {
  service_type: params.service_type,
  duration_minutes: params.duration_minutes || 30,
  days_ahead: params.days_ahead || 7,
  timestamp: new Date().toISOString()
};

const slots = $input.all()[0].json;
const formatted_slots = slots.available_slots.map(slot => ({
  date: slot.date,
  time: slot.time,
  available: slot.available
}));
return {
  status: 'success',
  data: {
    service_type: slots.service_type,
    duration: slots.duration,
    slots_table: formatted_slots,
    total_slots: formatted_slots.length
  }
};
